eckbox</span> <span class=\"fn\">CreateCheckbox</span>() =&gt; <span class=\"kw\">new</span> <span class=\"cl\">DarkCheckbox</span>();\n}\n\n<span class=\"cm\">// DI: services.AddSingleton<IUIFactory, DarkFactory>()</span>", "Python": "<span class=\"kw\">from</span> abc <span class=\"kw\">import</span> <span class=\"cl\">ABC</span>, abstractmethod\n\n<span class=\"kw\">class</span> <span class=\"cl\">UIFactory</span>(<span class=\"cl\">ABC</span>):\n  <span class=\"dc\">@abstractmethod</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">button</span>(<span class=\"dc\">self</span>): ...\n  <span class=\"dc\">@abstractmethod</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">checkbox</span>(<span class=\"dc\">self</span>): ...\n\n<span class=\"kw\">class</span> <span class=\"cl\">DarkFactory</span>(<span class=\"cl\">UIFactory</span>):\n  <span class=\"kw\">def</span> <span class=\"fn\">button</span>(<span class=\"dc\">self</span>):   <span class=\"kw\">return</span> <span class=\"cl\">DarkButton</span>()\n  <span class=\"kw\">def</span> <span class=\"fn\">checkbox</span>(<span class=\"dc\">self</span>): <span class=\"kw\">return</span> <span class=\"cl\">DarkCheckbox</span>()\n\n<span class=\"kw\">class</span> <span class=\"cl\">LightFactory</span>(<span class=\"cl\">UIFactory</span>):\n  <span class=\"kw\">def</span> <span class=\"fn\">button</span>(<span class=\"dc\">self</span>):   <span class=\"kw\">return</span> <span class=\"cl\">LightButton</span>()\n  <span class=\"kw\">def</span> <span class=\"fn\">checkbox</span>(<span class=\"dc\">self</span>): <span class=\"kw\">return</span> <span class=\"cl\">LightCheckbox</span>()", "Ruby": "<span class=\"kw\">module</span> <span class=\"cl\">UIFactory</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">button</span>   = <span class=\"kw\">raise</span> <span class=\"cl\">NotImplementedError</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">checkbox</span> = <span class=\"kw\">raise</span> <span class=\"cl\">NotImplementedError</span>\n<span class=\"kw\">end</span>\n\n<span class=\"kw\">class</span> <span class=\"cl\">DarkFactory</span>\n  <span class=\"kw\">include</span> <span class=\"cl\">UIFactory</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">button</span>   = <span class=\"cl\">DarkButton</span>.<span class=\"fn\">new</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">checkbox</span> = <span class=\"cl\">DarkCheckbox</span>.<span class=\"fn\">new</span>\n<span class=\"kw\">end</span>"}

